sql:
SELECT referee_name, nationality
FROM referees
WHERE nationality = 'Russia' AND experience > 5;

SELECT team_id, SUM(amount) AS total_sponsorship_revenue
FROM sponsorships
GROUP BY team_id;

SELECT goals
FROM match_stats
WHERE match_id = 0 AND team_id = 0;

SELECT SUM(amount) AS total_revenue
FROM sponsorships
WHERE team_id = 1;

SELECT team_1_id, team_2_id
FROM matches
WHERE attendance = (SELECT MAX(attendance) FROM matches);

external_knowledge:
- 'More successful teams' refers to teams that won more matches than the average team; 
- 'Scored more than the average number of goals' means their goal count was higher than the average goals scored in any match;
- 'Excelling beyond the typical team's winning rate' refers to having a higher number of matches won compared to the average number of matches won by all teams.

sql:
SELECT AVG(attendance) AS average_attendance
FROM matches
WHERE full_time_score = '0-0' AND half_time_score = '?';

SELECT match_id, referee_id
FROM match_referees
WHERE role = 'assistant referee';

SELECT SUM(fouls) 
FROM match_stats 
WHERE team_id = 1 AND match_id = 1;

SELECT referee_id, referee_name, nationality 
FROM referees 
WHERE experience > (SELECT AVG(experience) FROM referees);

SELECT team_name, coach_name, team_value, (SELECT MIN(team_value) FROM teams) AS min_value
FROM teams
WHERE team_value = (SELECT MIN(team_value) FROM teams);

SELECT match_id
FROM matches
WHERE attendance > (SELECT AVG(attendance) FROM matches);

SELECT referee_name
FROM referees
WHERE referee_id = 0 AND experience > 5;

SELECT sponsor_name, amount
FROM sponsorships
WHERE sponsorship_type = 'stadium';

external_knowledge:
- "most marketable player" refers to the player with the highest market value;
- "teams that have seen extensive action" means teams that have participated in more than 10 completed matches;
- "finished games" are matches whose status is 'completed'.
